export const handleBearerAuth = ({ verifyAccessToken, issuer, requiredScopes, audience, resource, showErrorDetails, }) => {
    if (typeof verifyAccessToken !== 'function') {
        throw new TypeError('`verifyAccessToken` must be a function that takes a token and returns an `AuthInfo` object.');
    }
    if (typeof issuer !== 'function' && typeof issuer !== 'string') {
        throw new TypeError('`issuer` must be either a string or a function that validates the token issuer.');
    }
    if (typeof issuer === 'string' && !trySafe(() => new URL(issuer))) {
        throw new TypeError(`\`issuer\` must be a valid URL.`);
    }
    const bearerAuthHandler = async function (request, response, next) {
        try {
            const token = getBearerTokenFromHeaders(request.headers);
            const authInfo = await verifyAccessToken(token);
            if (typeof issuer === 'function') {
                issuer(authInfo.issuer);
            }
            else {
                /**
                 * When issuer is provided as a string, directly compare it with the token's issuer value
                 */
                // eslint-disable-next-line no-lonely-if
                if (authInfo.issuer !== issuer) {
                    throw new MCPAuthBearerAuthError('invalid_issuer', {
                        expected: issuer,
                        actual: authInfo.issuer,
                    });
                }
            }
            if (audience &&
                (Array.isArray(authInfo.audience)
                    ? !authInfo.audience.includes(audience)
                    : authInfo.audience !== audience)) {
                throw new MCPAuthBearerAuthError('invalid_audience', {
                    expected: audience,
                    actual: authInfo.audience,
                });
            }
            if (requiredScopes) {
                const missingScopes = requiredScopes.filter((scope) => !authInfo.scopes.includes(scope));
                if (missingScopes.length > 0) {
                    throw new MCPAuthBearerAuthError('missing_required_scopes', {
                        missingScopes,
                    });
                }
            }
            if (request.auth) {
                console.warn('Request already contains auth info and will be overwritten. Please double-check if this is intended.');
            }
            // eslint-disable-next-line @silverhand/fp/no-mutation
            request.auth = authInfo;
            next();
        }
        catch (error) {
            handleError(error, response, cond(resource && createResourceMetadataEndpoint(resource).toString()), showErrorDetails);
        }
    };
    return bearerAuthHandler;
};
